{
  "citations": [
    {
      "span_start": 218,
      "span_end": 257,
      "span_text": "وَمَا نُنَزِّلُهُ إِلَّا بِقَدَرٍ مَعْلُومٍ",
      "citation_type": "Aya"
    },
    {
      "span_start": 374,
      "span_end": 557,
      "span_text": "إن أحَدَكُمْ يُجْمَعُ خَلْقُهُ في بَطْنِ أُمِّهِ أَرْبَعِينَ يَوْمَاً نُطْفَةً، ثُمَّ يَكُونُ عَلَقَةً مِثْلَ ذلكَ، ثُمَّ يَكُونُ مُضْغَةً مِثْلَ ذلكَ، ثُمَّ يُرْسَلُ المَلَكُ فَيَنْفُخُ فِيهِ الرُّوحَ، وَيُؤْمَرُ بأرْبَعِ كَلِماتٍ: بِكَتْب رِزْقِهِ وَأجَلِهِ وَعَمَلِهِ وَشَقِيٍّ أَوْ سَعِيدٍ",
      "citation_type": "Hadeeth"
    },
    {
      "span_start": 1030,
      "span_end": 1124,
      "span_text": "فِي يَوْمَيْنِ وَتَجْعَلُونَ لَهُ أَندَاداً ذَلِكَ رَبُّ العالمين وَجَعَلَ فِيهَا رَوَاسِيَ مِن فَوْقِهَا وَبَارَكَ فِيهَا وَقَدَّرَ فِيهَآ أَقْوَاتَهَا في أَرْبَعَةِ أَيَّامٍ سَوَآءً لِّلسَّآئِلِينَ",
      "citation_type": "Aya"
    },
    {
      "span_start": 1160,
      "span_end": 1211,
      "span_text": "وَمَا نُنَزِّلُهُ إِلاَّ بِقَدَرٍ مَّعْلُومٍ",
      "citation_type": "Aya"
    },
    {
      "span_start": 1393,
      "span_end": 1452,
      "span_text": "وَمَا مِنْ دَابَّةٍ فِي الْأَرْضِ إِلَّا عَلَى اللَّهِ رِزْقُهَا",
      "citation_type": "Aya"
    },
    {
      "span_start": 1481,
      "span_end": 1550,
      "span_text": "وَكَأَيِّنْ مِنْ دَابَّةٍ لا تَحْمِلُ رِزْقَهَا اللَّهُ يَرْزُقُهَا وَإِيَّاكُمْ",
      "citation_type": "Aya"
    },
    {
      "span_start": 1579,
      "span_end": 1638,
      "span_text": "مَا يَفْتَحِ اللَّهُ لِلنَّاسِ مِنْ رَحْمَةٍ فَلا مُمْسِكَ لَهَا",
      "citation_type": "Aya"
    },
    {
      "span_start": 1667,
      "span_end": 1719,
      "span_text": "وَإِنْ يُرِدْكَ بِخَيْرٍ فَلا رَادَّ لِفَضْلِهِ",
      "citation_type": "Aya"
    },
    {
      "span_start": 1770,
      "span_end": 1952,
      "span_text": "إنَّ أحَدَكُمْ يُجْمَعُ خَلْقُهُ في بَطْنِ أُمِّهِ أَرْبَعِينَ يَوْمَاً نُطْفَةً، ثُمَّ يَكُونُ عَلَقَةً مِثْلَ ذلكَ، ثُمَّ يَكُونُ مُضْغَةً مِثْلَ ذلكَ، ثُمَّ يُرْسَلُ المَلَكُ فَيَنْفُخُ فِيهِ الرُّوحَ، وَيُؤْمَرُ بأرْبَعِ كَلِماتٍ: بِكَتْب رِزْقِهِ وَأَجَلِهِ وَعَمَلِهِ وَشَقِيٍّ أَوْ سَعِيدٍ",
      "citation_type": "Hadeeth"
    },
    {
      "span_start": 2248,
      "span_end": 2348,
      "span_text": "وَضَرَبَ الله مَثَلاً قَرْيَةً كَانَتْ آمِنَةً مُّطْمْئِنَّةً يَأْتِيهَا رِزْقُهَا رَغَداً مِّن كُلِّ مَكَانٍ فَكَفَرَتْ بِأَنْعُمِ الله فَأَذَاقَهَا الله لِبَاسَ الجوع والخوف بِمَا كَانُواْ يَصْنَعُونَ",
      "citation_type": "Aya"
    },
    {
      "span_start": 2478,
      "span_end": 2569,
      "span_text": "إِنَّ الذين تَوَفَّاهُمُ الملائكة ظالمي أَنْفُسِهِمْ قَالُواْ فِيمَ كُنتُمْ قَالُواْ كُنَّا مُسْتَضْعَفِينَ فِي الأرض قالوا أَلَمْ تَكُنْ أَرْضُ الله وَاسِعَةً فَتُهَاجِرُواْ فِيهَا",
      "citation_type": "Aya"
    }
  ]
}
